export const privacyHtml = "<!-- 서문 -->\n    <div class=\"bg-white rounded-xl shadow-sm border border-gray-100 p-6 mb-6\" style=\"border-left:4px solid var(--amber-400);\">\n        <p class=\"text-sm text-gray-700\" style=\"line-height:1.8;margin:0;\">\n            유니스오더(이하 \"서비스\")를 운영하는 HOURGRIT(이하 \"회사\")은 「개인정보 보호법」 제30조에 따라 이용자의 개인정보를 보호하고,\n            관련 고충을 신속하고 원활하게 처리할 수 있도록 다음과 같이 개인정보처리방침을 수립하여 공개합니다.\n            본 방침은 이용약관에서 정의한 바와 같이 회사가 제공하는 유니스오더 서비스 및 관련 부가 서비스 이용에 적용됩니다.\n        </p>\n    </div>\n\n    <!-- TOC -->\n    <div class=\"bg-white rounded-xl shadow-sm border border-gray-100 p-6 mb-6\">\n        <h2 class=\"text-base font-bold text-gray-900 mb-4\" style=\"margin:0 0 16px;\">목차</h2>\n        <div class=\"toc-grid\">\n            <a href=\"#p1\" class=\"toc-link\"><span>제1조</span> 개인정보의 처리 목적</a>\n            <a href=\"#p2\" class=\"toc-link\"><span>제2조</span> 보유 및 이용 기간</a>\n            <a href=\"#p3\" class=\"toc-link\"><span>제3조</span> 처리하는 개인정보 항목</a>\n            <a href=\"#p4\" class=\"toc-link\"><span>제4조</span> 제3자 제공</a>\n            <a href=\"#p5\" class=\"toc-link\"><span>제5조</span> 처리 위탁</a>\n            <a href=\"#p6\" class=\"toc-link\"><span>제6조</span> 정보주체의 권리·의무</a>\n            <a href=\"#p7\" class=\"toc-link\"><span>제7조</span> 개인정보의 파기</a>\n            <a href=\"#p8\" class=\"toc-link\"><span>제8조</span> 안전성 확보 조치</a>\n            <a href=\"#p9\" class=\"toc-link\"><span>제9조</span> 쿠키의 사용</a>\n            <a href=\"#p10\" class=\"toc-link\"><span>제10조</span> 오픈마켓 데이터 보호정책 준수</a>\n            <a href=\"#p11\" class=\"toc-link\"><span>제11조</span> 국제 데이터 이전</a>\n            <a href=\"#p12\" class=\"toc-link\"><span>제12조</span> 아동의 개인정보 보호</a>\n            <a href=\"#p13\" class=\"toc-link\"><span>제13조</span> 개인정보 보호책임자</a>\n            <a href=\"#p14\" class=\"toc-link\"><span>제14조</span> 방침의 변경</a>\n        </div>\n    </div>\n\n    <!-- Content -->\n    <article class=\"bg-white rounded-xl shadow-sm border border-gray-100 px-6 lg:px-10 legal-content\">\n\n        <!-- 제1조 -->\n        <section id=\"p1\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제1조</span> 개인정보의 처리 목적</h2>\n            <div class=\"legal-body\">\n                <p>회사는 다음의 목적을 위하여 최소한의 개인정보를 처리합니다. 처리하고 있는 개인정보는 명시된 목적 이외의 용도로는 이용되지 않으며, 이용 목적이 변경되는 경우에는 관련 법령에 따라 별도의 동의를 받는 등 필요한 조치를 이행할 예정입니다.</p>\n                <ol>\n                    <li><strong>서비스 이용계약의 체결 및 계정 관리:</strong> 연동서비스(Google 등)를 통한 이용자 식별, 서비스 이용계약의 체결 및 승낙, 이용자 정보의 관리 및 서비스 제공 부적격자(만 14세 미만 등)의 확인</li>\n                    <li><strong>서비스 제공 및 이행:</strong> 오픈마켓 주문 정보 수집 및 API 서비스 연동 관리, 송장 출력, 상품 및 재고 등록 관리, 이미지호스팅 및 세팅 서비스 등 부가 서비스 제공</li>\n                    <li><strong>결제 및 정산:</strong> 정기결제 처리, 부가 서비스 이용료 결제, 서비스 이용료의 환불 및 과납·오납 처리</li>\n                    <li><strong>고객 상담 및 불만 처리:</strong> 서비스 이용 중 발생하는 기술 지원 및 민원 사항에 대한 이메일 답변, 서비스 장애 및 약관 개정 등 주요 고지사항 전달</li>\n                    <li><strong>서비스 개선:</strong> 서비스 이용 현황 분석 및 서비스 품질 개선, 보안 강화</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제2조 -->\n        <section id=\"p2\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제2조</span> 개인정보의 보유 및 이용 기간</h2>\n            <div class=\"legal-body\">\n                <p>회사는 관련 법령에 따른 개인정보 보유·이용기간 또는 이용자로부터 개인정보 수집 시에 동의받은 기간 내에서 개인정보를 처리·보유합니다.</p>\n                <ol>\n                    <li><strong>관련 법령에 따른 보존 (전자상거래 등에서의 소비자보호에 관한 법률)</strong>\n                        <ul>\n                            <li>계약 또는 청약철회 등에 관한 기록: 5년</li>\n                            <li>대금결제 및 재화 등의 공급에 관한 기록: 5년</li>\n                            <li>소비자의 불만 또는 분쟁처리에 관한 기록: 3년</li>\n                        </ul>\n                    </li>\n                    <li><strong>서비스 로그 및 접속 기록 (통신비밀보호법)</strong>\n                        <ul>\n                            <li>웹사이트 접속 기록: 3개월</li>\n                        </ul>\n                    </li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제3조 -->\n        <section id=\"p3\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제3조</span> 처리하는 개인정보 항목</h2>\n            <div class=\"legal-body\">\n                <p>회사는 서비스 제공을 위해 아래와 같은 개인정보 항목을 수집하고 있습니다.</p>\n                <table class=\"legal-table\">\n                    <thead>\n                        <tr>\n                            <th>구분</th>\n                            <th>수집 항목</th>\n                            <th>수집 방법</th>\n                        </tr>\n                    </thead>\n                    <tbody>\n                        <tr>\n                            <td>회원 가입 (연동서비스)</td>\n                            <td>이름, 이메일 주소, 프로필 이미지(선택), 연동 계정 고유 식별값(UID)</td>\n                            <td>Google 연동서비스로부터 제공</td>\n                        </tr>\n                        <tr>\n                            <td>서비스 이용 (필수)</td>\n                            <td>회사명(매장명), 대표자명, 사업자등록번호, 오픈마켓 API 인증키 및 연동 정보</td>\n                            <td>이용자 직접 입력 및 API 연동</td>\n                        </tr>\n                        <tr>\n                            <td>결제 정보</td>\n                            <td>신용카드 정보(카드사명, 마스킹된 카드번호), 결제 및 환불 기록</td>\n                            <td>토스페이먼츠 결제 모듈 연동</td>\n                        </tr>\n                        <tr>\n                            <td>자동 수집 항목</td>\n                            <td>IP주소, 쿠키, 서비스 접속 및 이용 기록, 브라우저 및 OS 정보</td>\n                            <td>서비스 이용 과정 중 자동 생성</td>\n                        </tr>\n                    </tbody>\n                </table>\n            </div>\n        </section>\n\n        <!-- 제4조 -->\n        <section id=\"p4\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제4조</span> 개인정보의 제3자 제공</h2>\n            <div class=\"legal-body\">\n                <p>회사는 이용자의 사전 동의 없이는 이용자의 개인정보를 외부에 제공하지 않습니다. 다만, 다음의 경우에 한하여 예외로 합니다.</p>\n                <ol>\n                    <li>이용자가 사전에 제3자 제공 및 공개에 동의한 경우</li>\n                    <li>법령의 규정에 의거하거나, 수사 목적으로 법령에 정해진 절차와 방법에 따라 수사기관의 요구가 있는 경우</li>\n                    <li>통계 작성, 학술 연구, 시장 조사 등을 위하여 특정 개인을 식별할 수 없는 형태로 가공하여 제공하는 경우</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제5조 -->\n        <section id=\"p5\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제5조</span> 개인정보의 처리 위탁</h2>\n            <div class=\"legal-body\">\n                <p>회사는 원활한 서비스 운영을 위해 다음과 같이 개인정보 처리업무를 외부에 위탁하고 있으며, 위탁계약 시 개인정보가 안전하게 관리될 수 있도록 필요한 사항을 규정하고 있습니다.</p>\n                <table class=\"legal-table\">\n                    <thead>\n                        <tr>\n                            <th>수탁업체</th>\n                            <th>위탁 업무 내용</th>\n                        </tr>\n                    </thead>\n                    <tbody>\n                        <tr>\n                            <td>토스페이먼츠(주)</td>\n                            <td>정기결제 및 부가서비스 이용료 결제 처리, 결제 수단 인증</td>\n                        </tr>\n                        <tr>\n                            <td>Google Cloud Platform</td>\n                            <td>웹 서비스 제공을 위한 서버 운영 및 데이터 보관 (인프라 위탁)</td>\n                        </tr>\n                    </tbody>\n                </table>\n                <p>위탁업체가 변경되는 경우 본 개인정보처리방침을 통하여 공개하겠습니다.</p>\n            </div>\n        </section>\n\n        <!-- 제6조 -->\n        <section id=\"p6\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제6조</span> 정보주체의 권리·의무 및 그 행사방법</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>이용자는 언제든지 회사에 대해 다음의 권리를 행사할 수 있습니다.\n                        <ul>\n                            <li>개인정보 열람 요구</li>\n                            <li>오류 등이 있을 경우 정정 요구</li>\n                            <li>삭제 요구</li>\n                            <li>처리정지 요구</li>\n                        </ul>\n                    </li>\n                    <li>권리 행사는 이메일(<a href=\"mailto:contact@hourgrit.com\">contact@hourgrit.com</a>) 또는 카카오톡 채널(@unisorder)을 통하여 신청하실 수 있으며, 회사는 이에 대해 지체 없이 조치하겠습니다.</li>\n                    <li>이용자가 개인정보의 오류 등에 대한 정정 또는 삭제를 요구한 경우에는 정정 또는 삭제를 완료할 때까지 당해 개인정보를 이용하거나 제공하지 않습니다.</li>\n                    <li>권리 행사는 이용자의 법정대리인이나 위임을 받은 자 등 대리인을 통하여서도 하실 수 있습니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제7조 -->\n        <section id=\"p7\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제7조</span> 개인정보의 파기</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>회사는 이용계약 해지(회원 탈퇴) 시 또는 개인정보 보유기간이 경과한 경우 해당 정보를 지체 없이 파기합니다.</li>\n                    <li>이용약관에 따라 휴면계정으로 분류되어 서비스 이용계약이 해지되는 경우에도 관련 법령에 따른 보존 필요성이 없는 한 해당 정보를 파기합니다.</li>\n                    <li>파기 방법:\n                        <ul>\n                            <li>전자적 파일 형태: 복원이 불가능한 방법으로 영구 삭제</li>\n                            <li>종이 문서: 분쇄기로 분쇄하거나 소각</li>\n                        </ul>\n                    </li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제8조 -->\n        <section id=\"p8\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제8조</span> 개인정보의 안전성 확보 조치</h2>\n            <div class=\"legal-body\">\n                <p>회사는 개인정보의 안전성 확보를 위해 다음과 같은 조치를 취하고 있습니다.</p>\n                <ol>\n                    <li><strong>기술적 조치:</strong> 연동서비스 기반의 보안 인증 적용(Google OAuth), 개인정보 저장 및 전송 시 암호화(TLS/SSL), JWT 기반 접근 토큰 관리, 보안 프로그램 설치 및 갱신</li>\n                    <li><strong>관리적 조치:</strong> 개인정보 접근 권한의 차등 부여 및 최소화, 내부 관리 계획의 수립 및 시행</li>\n                    <li><strong>물리적 조치:</strong> 클라우드 서비스(GCP) 기반의 안전한 데이터 센터 이용</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제9조 -->\n        <section id=\"p9\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제9조</span> 쿠키의 사용</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>회사는 이용자에게 최적화된 서비스를 제공하기 위하여 쿠키(Cookie)를 사용합니다.</li>\n                    <li>쿠키의 사용 목적:\n                        <ul>\n                            <li>로그인 세션 유지</li>\n                            <li>이용자 설정 및 환경 기억</li>\n                            <li>서비스 이용 현황 분석 및 개선</li>\n                        </ul>\n                    </li>\n                    <li>이용자는 웹 브라우저의 설정을 통해 쿠키를 허용하거나 거부할 수 있습니다. 다만, 쿠키를 거부할 경우 서비스 일부 기능의 이용이 제한될 수 있습니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제10조 - 오픈마켓 DPP -->\n        <section id=\"p10\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제10조</span> 오픈마켓 데이터 보호정책 준수</h2>\n            <div class=\"legal-body\">\n                <p>유니스오더는 연동된 각 오픈마켓의 데이터 보호정책(Data Protection Policy)을 준수하며, 오픈마켓 API를 통해 수집되는 고객 정보에 대해 다음과 같은 엄격한 보호 조치를 시행합니다.</p>\n\n                <div class=\"dpp-highlight\">\n                    <p style=\"font-weight:600;color:var(--primary-dark);margin-bottom:6px;\">개인식별정보(PII) 마스킹</p>\n                    <ul>\n                        <li><strong>고객 이름:</strong> 마스킹 처리되어 일반 식별자로만 표시 (예: \"[MASKED] Customer-***89\")</li>\n                        <li><strong>전화번호 / 배송 주소 / 이메일 주소:</strong> 시스템에 저장 또는 표시하지 않음</li>\n                        <li><strong>시각적 표시:</strong> 모든 마스킹 데이터는 인터페이스 전반에 걸쳐 [MASKED] 태그로 명확히 표시</li>\n                    </ul>\n                </div>\n\n                <div class=\"dpp-highlight\">\n                    <p style=\"font-weight:600;color:var(--primary-dark);margin-bottom:6px;\">데이터 저장 정책</p>\n                    <ul>\n                        <li>익명화된 거래 데이터(주문 ID, 금액, 주문 상태)만 데이터베이스에 저장</li>\n                        <li>모든 개인식별정보(PII)는 해당 오픈마켓의 보안 시스템에만 보관</li>\n                        <li>데이터 흐름의 어떤 단계에서도 고객 PII가 데이터베이스에 기록되지 않음</li>\n                        <li>API 응답 데이터는 데이터베이스 저장 전 PII를 필터링하여 제거</li>\n                    </ul>\n                </div>\n\n                <div class=\"dpp-highlight\">\n                    <p style=\"font-weight:600;color:var(--primary-dark);margin-bottom:6px;\">데이터 보존 정책</p>\n                    <ul>\n                        <li>거래 데이터는 각 오픈마켓의 데이터 보호정책에서 정한 기간 내에서만 표시</li>\n                        <li>보존 기간이 경과한 거래 데이터는 자동으로 시스템에서 제거</li>\n                        <li>대시보드에 보존 기간을 명확히 표시</li>\n                    </ul>\n                </div>\n\n                <div class=\"dpp-highlight\">\n                    <p style=\"font-weight:600;color:var(--primary-dark);margin-bottom:6px;\">제3자 데이터 공유 제한</p>\n                    <ul>\n                        <li>AI 서비스 제공자에게 고객 PII를 공유하지 않음 (상품 설명 생성만 수행)</li>\n                        <li>분석 서비스에는 익명화·집계된 데이터만 제공</li>\n                        <li>모든 데이터 공유는 익명화된 사업 거래 데이터에 한정</li>\n                    </ul>\n                </div>\n            </div>\n        </section>\n\n        <!-- 제11조 -->\n        <section id=\"p11\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제11조</span> 국제 데이터 이전</h2>\n            <div class=\"legal-body\">\n                <p>대한민국 이외의 지역에서 유니스오더에 접속하는 경우, 이용자의 데이터는 서버가 위치한 대한민국(GCP asia-northeast3, 서울 리전)으로 전송되어 처리될 수 있습니다. 회사는 관련 데이터 보호 법령에 따라 적절한 안전 조치를 시행합니다.</p>\n            </div>\n        </section>\n\n        <!-- 제12조 -->\n        <section id=\"p12\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제12조</span> 아동의 개인정보 보호</h2>\n            <div class=\"legal-body\">\n                <p>유니스오더는 사업자를 대상으로 하는 서비스이며, 만 14세 미만 아동을 대상으로 하지 않습니다. 회사는 만 14세 미만 아동의 개인정보를 의도적으로 수집하지 않으며, 만 14세 미만 아동의 개인정보가 수집된 사실을 알게 된 경우 해당 정보를 즉시 파기합니다.</p>\n            </div>\n        </section>\n\n        <!-- 제13조 -->\n        <section id=\"p13\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제13조</span> 개인정보 보호책임자</h2>\n            <div class=\"legal-body\">\n                <p>회사는 이용자의 개인정보 관련 문의 및 불만 처리를 위하여 아래와 같이 개인정보 보호책임자를 지정하고 있습니다.</p>\n                <table class=\"legal-table\">\n                    <tbody>\n                        <tr><th style=\"width:120px;\">성명</th><td>박상현</td></tr>\n                        <tr><th>직책</th><td>대표</td></tr>\n                        <tr><th>이메일</th><td><a href=\"mailto:contact@hourgrit.com\">contact@hourgrit.com</a></td></tr>\n                        <tr><th>카카오톡 채널</th><td>@unisorder (<a href=\"https://pf.kakao.com/_unisorder\" target=\"_blank\" rel=\"noreferrer\">바로가기</a>)</td></tr>\n                    </tbody>\n                </table>\n                <p>이용자는 서비스를 이용하면서 발생하는 모든 개인정보 보호 관련 문의, 불만처리, 피해구제 등에 관한 사항을 위 연락처로 문의하실 수 있으며, 회사는 이용자의 문의에 지체 없이 답변 및 처리하겠습니다.</p>\n                <p>기타 개인정보침해에 대한 신고나 상담이 필요하신 경우 아래 기관에 문의하시기 바랍니다.</p>\n                <ul>\n                    <li>개인정보침해신고센터: (국번없이) 118 / privacy.kisa.or.kr</li>\n                    <li>개인정보분쟁조정위원회: (국번없이) 1833-6972 / www.kopico.go.kr</li>\n                    <li>대검찰청 사이버수사과: (국번없이) 1301 / www.spo.go.kr</li>\n                    <li>경찰청 사이버수사국: (국번없이) 182 / ecrm.cyber.go.kr</li>\n                </ul>\n            </div>\n        </section>\n\n        <!-- 제14조 -->\n        <section id=\"p14\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제14조</span> 개인정보처리방침의 변경</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>이 개인정보처리방침은 <strong>2026년 3월 13일</strong>부터 적용됩니다.</li>\n                    <li>본 방침의 내용 추가, 삭제 및 수정이 있을 시에는 시행 7일 전부터 서비스 내 공지사항을 통해 고지하겠습니다. 다만, 이용자의 권리에 중요한 변경이 있을 경우에는 시행 30일 전부터 고지하겠습니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 부칙 -->\n        <section class=\"legal-article\" style=\"border-top: 2px solid var(--gray-300);\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\" style=\"background:var(--gray-700);\">부칙</span></h2>\n            <div class=\"legal-body\">\n                <p>본 개인정보처리방침은 <strong>2026년 3월 13일</strong>부터 시행합니다.</p>\n            </div>\n        </section>\n    </article>";

export const termsHtml = "<!-- 안내 -->\n    <div class=\"bg-white rounded-xl shadow-sm border border-gray-100 p-6 mb-6\" style=\"border-left:4px solid var(--amber-400);\">\n        <p class=\"text-sm text-gray-700\" style=\"line-height:1.8;margin:0;\">\n            <strong>안내:</strong> 본 이용약관을 주의 깊게 읽어주시기 바랍니다. 계정을 생성하거나 서비스를 이용함으로써, 이용자는 본 약관 및\n            <a href=\"/privacy\">개인정보처리방침</a>을 읽고 이해하였으며 이에 동의하는 것으로 간주됩니다.\n        </p>\n    </div>\n\n    <!-- TOC -->\n    <div class=\"bg-white rounded-xl shadow-sm border border-gray-100 p-6 mb-6\">\n        <h2 class=\"text-base font-bold text-gray-900 mb-4\" style=\"margin:0 0 16px;\">목차</h2>\n        <div class=\"toc-grid\">\n            <a href=\"#a1\" class=\"toc-link\"><span>제1조</span> 목적</a>\n            <a href=\"#a2\" class=\"toc-link\"><span>제2조</span> 용어의 정의</a>\n            <a href=\"#a3\" class=\"toc-link\"><span>제3조</span> 약관의 게시와 개정</a>\n            <a href=\"#a4\" class=\"toc-link\"><span>제4조</span> 약관 외 준칙</a>\n            <a href=\"#a5\" class=\"toc-link\"><span>제5조</span> 이용계약의 체결</a>\n            <a href=\"#a6\" class=\"toc-link\"><span>제6조</span> 개인정보 수집 및 보호</a>\n            <a href=\"#a7\" class=\"toc-link\"><span>제7조</span> 계정 관리</a>\n            <a href=\"#a8\" class=\"toc-link\"><span>제8조</span> 이용자에 대한 통지</a>\n            <a href=\"#a9\" class=\"toc-link\"><span>제9조</span> 회사의 의무</a>\n            <a href=\"#a10\" class=\"toc-link\"><span>제10조</span> 이용자의 의무</a>\n            <a href=\"#a11\" class=\"toc-link\"><span>제11조</span> 서비스 제공</a>\n            <a href=\"#a12\" class=\"toc-link\"><span>제12조</span> 서비스의 변경 또는 중단</a>\n            <a href=\"#a13\" class=\"toc-link\"><span>제13조</span> 서비스 이용의 제한 및 정지</a>\n            <a href=\"#a14\" class=\"toc-link\"><span>제14조</span> 오픈마켓 연동 및 API 사용</a>\n            <a href=\"#a15\" class=\"toc-link\"><span>제15조</span> AI 기능 이용 준수사항</a>\n            <a href=\"#a16\" class=\"toc-link\"><span>제16조</span> 구독 및 결제</a>\n            <a href=\"#a17\" class=\"toc-link\"><span>제17조</span> 이용요금 등의 환불</a>\n            <a href=\"#a18\" class=\"toc-link\"><span>제18조</span> 이용계약 해지</a>\n            <a href=\"#a19\" class=\"toc-link\"><span>제19조</span> 데이터의 보관 및 삭제</a>\n            <a href=\"#a20\" class=\"toc-link\"><span>제20조</span> 지식재산권</a>\n            <a href=\"#a21\" class=\"toc-link\"><span>제21조</span> 면책조항 및 책임 제한</a>\n            <a href=\"#a22\" class=\"toc-link\"><span>제22조</span> 손해배상</a>\n            <a href=\"#a23\" class=\"toc-link\"><span>제23조</span> 불만처리</a>\n            <a href=\"#a24\" class=\"toc-link\"><span>제24조</span> 준거법 및 분쟁 해결</a>\n            <a href=\"#a25\" class=\"toc-link\"><span>제25조</span> 기타</a>\n        </div>\n    </div>\n\n    <!-- Content -->\n    <article class=\"bg-white rounded-xl shadow-sm border border-gray-100 px-6 lg:px-10 legal-content\">\n\n        <!-- 제1조 -->\n        <section id=\"a1\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제1조</span> 목적</h2>\n            <div class=\"legal-body\">\n                <p>본 약관은 HOURGRIT(이하 \"회사\")이 제공하는 유니스오더(이하 통칭하여 \"서비스\")의 이용과 관련하여 회사와 이용자의 권리·의무 및 책임사항, 기타 필요한 사항을 규정함을 목적으로 합니다.</p>\n            </div>\n        </section>\n\n        <!-- 제2조 -->\n        <section id=\"a2\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제2조</span> 용어의 정의</h2>\n            <div class=\"legal-body\">\n                <p>본 약관에서 사용하는 용어의 정의는 다음과 같습니다.</p>\n                <ol>\n                    <li><strong>\"서비스\"</strong>란 회사가 제공하는 유니스오더 SaaS(Software as a Service) 플랫폼으로, 오픈마켓 셀러를 위한 주문 관리, 상품 관리, 재고 관리, 매출 분석 등 온라인 셀러 통합 관리 서비스를 말합니다.</li>\n                    <li><strong>\"이용자\"</strong>란 본 약관에 따라 회사와 서비스 이용계약을 체결하고 회사가 제공하는 서비스를 이용하는 개인 또는 기업을 의미합니다.</li>\n                    <li><strong>\"서비스 계정(ID)\"</strong>이란 이용자 식별과 서비스 이용을 위하여 이용자가 보유한 외부 서비스(Google 등)의 계정을 연동하여 회사가 승인한 식별 정보를 의미합니다. 본 서비스는 별도의 자체 아이디 및 비밀번호 설정을 지원하지 않으며 외부 소셜 로그인 방식을 통해 제공됩니다.</li>\n                    <li><strong>\"연동서비스\"</strong>란 이용자가 서비스에 로그인하기 위해 사용하는 외부 플랫폼(Google)의 인증 서비스를 말합니다.</li>\n                    <li><strong>\"오픈마켓\"</strong>이란 이용자가 상품을 판매하는 온라인 이커머스 플랫폼(Shopee, Lazada, eBay, Qoo10, TikTok Shop 등)을 말합니다.</li>\n                    <li><strong>\"오픈마켓 연동\"</strong>이란 이용자가 운영하는 오픈마켓 스토어를 서비스에 연결하여 API(Application Programming Interface)를 통해 데이터를 동기화하는 것을 말합니다.</li>\n                    <li><strong>\"구독\"</strong>이란 이용자가 유료 서비스를 일정 기간 단위로 결제하고 이용하는 것을 말합니다.</li>\n                    <li><strong>\"정기결제\"</strong>란 이용자의 신청에 따라 이용자가 지정한 결제수단을 통하여 정기적으로 서비스 이용요금의 결제가 이루어지는 것을 말합니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제3조 -->\n        <section id=\"a3\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제3조</span> 약관의 게시와 개정</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>회사는 본 약관의 내용을 이용자가 쉽게 알 수 있도록 서비스 홈페이지(www.unisorder.com)에 게시합니다.</li>\n                    <li>회사는 전기통신사업법, 약관의 규제에 관한 법률, 개인정보보호법, 정보통신망법, 전자상거래 등에서의 소비자 보호에 관한 법률 등 관련법을 위배하지 않는 범위에서 본 약관을 개정할 수 있습니다.</li>\n                    <li>회사가 약관을 개정할 경우에는 적용일자 및 개정사유를 명시하여 현행약관과 함께 그 개정약관의 적용일자 7일 전부터 적용일자 전까지 홈페이지에 공지합니다. 다만, 이용자의 권리 또는 의무에 관한 중요한 규정의 변경은 최소한 30일 전에 공지하고 이용자가 등록한 이메일 등으로 별도로 통지합니다.</li>\n                    <li>회사가 전항에 따라 개정약관을 공지 또는 통지하면서 이용자에게 약관 변경 적용일까지 거부의사를 표시하지 않으면 동의한 것으로 본다는 뜻을 명확하게 공지 또는 통지하였음에도 이용자가 명시적으로 거부의 의사표시를 하지 아니한 경우 이용자가 개정약관에 동의한 것으로 봅니다.</li>\n                    <li>이용자가 개정약관의 적용에 동의하지 않을 경우 회사는 개정약관의 내용을 적용할 수 없으며, 이 경우 이용자는 이용계약을 해지할 수 있습니다. 다만, 기존 약관을 적용할 수 없는 특별한 사정이 있는 경우에는 회사는 이용계약을 해지할 수 있습니다.</li>\n                    <li>본 약관은 이용자가 약관의 내용에 동의함으로써 효력이 발생하며 이용계약 종료일까지 적용됩니다. 단, 채권 또는 채무관계가 있을 경우에는 채권·채무의 완료일까지로 규정합니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제4조 -->\n        <section id=\"a4\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제4조</span> 약관 외 준칙</h2>\n            <div class=\"legal-body\">\n                <p>본 약관에서 정하지 않은 사항과 본 약관의 해석에 관하여는 전기통신사업법, 개인정보보호법, 정보통신망법, 전자상거래 등에서의 소비자보호에 관한 법률, 약관의 규제에 관한 법률 및 기타 관계법령 또는 상관례에 따릅니다.</p>\n            </div>\n        </section>\n\n        <!-- 제5조 -->\n        <section id=\"a5\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제5조</span> 이용계약의 체결</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>이용계약은 가입신청자가 본 약관의 내용에 대하여 동의를 한 다음, 회사가 제공하는 외부 연동서비스(Google 등)를 통해 인증을 완료하고 회사가 이러한 신청에 대하여 승낙함으로써 체결됩니다.</li>\n                    <li>이용자는 서비스 이용을 위해 다음 요건을 충족하여야 합니다.\n                        <ul>\n                            <li>만 14세 이상일 것</li>\n                            <li>정확하고 완전한 가입 정보를 제공할 것</li>\n                            <li>관련 법령을 준수할 것</li>\n                        </ul>\n                    </li>\n                    <li>제1항에 따른 회사 승낙에도 불구하고 이용자는 이용요금을 선납하기 전까지는 유료서비스의 이용을 개시할 수 없습니다.</li>\n                    <li>회사는 가입신청자의 신청에 대하여 서비스 이용을 승낙함을 원칙으로 합니다. 다만, 회사는 다음 각 호에 해당하는 신청에 대하여는 승낙을 하지 않거나 사후에 이용계약을 해지할 수 있습니다.\n                        <ul>\n                            <li>타인의 외부 서비스 계정을 도용하여 신청하거나 실명이 아닌 경우</li>\n                            <li>외부 연동서비스 자체의 결함이나 탈퇴 등으로 인증이 불가능한 경우</li>\n                            <li>허위의 정보를 기재하거나, 회사가 제시하는 내용을 기재하지 않은 경우</li>\n                            <li>만 14세 미만의 가입자인 경우</li>\n                            <li>이용자가 서비스의 정상적인 제공을 저해하거나 다른 이용자의 서비스 이용에 지장을 줄 것으로 예상되는 경우</li>\n                            <li>제18조 제3항에 의하여 회사로부터 계약해지를 당한 이후 1년이 경과하지 않은 경우</li>\n                            <li>기타 회사가 관련법령 등을 기준으로 하여 명백하게 사회질서 및 미풍양속에 반할 우려가 있음을 인정하는 경우</li>\n                        </ul>\n                    </li>\n                    <li>회사는 설비의 부족이나 기술적 장애, 서비스 상의 장애가 발생한 경우 승낙을 지연할 수 있습니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제6조 -->\n        <section id=\"a6\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제6조</span> 개인정보 수집 및 보호</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>회사는 외부 연동서비스로부터 제공받는 정보(이메일, 프로필 정보 등)를 포함하여 이용계약 이행에 필요한 최소한의 개인정보를 수집합니다.</li>\n                    <li>회사는 개인정보보호법, 정보통신망법 등 관계 법령이 정하는 바에 따라 이용자의 개인정보를 보호하기 위해 노력합니다.</li>\n                    <li>개인정보의 보호 및 사용에 대해서는 관련법 및 회사의 <a href=\"/privacy\">개인정보처리방침</a>이 적용됩니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제7조 -->\n        <section id=\"a7\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제7조</span> 계정 관리</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>서비스는 별도의 자체 비밀번호를 저장하지 않으므로, 이용자는 연동된 외부 서비스(Google 등) 계정 및 비밀번호에 대한 관리 책임을 직접 부담합니다.</li>\n                    <li>이용자의 외부 계정 관리 소홀이나 제3자의 부정 사용으로 인하여 발생하는 모든 손해에 대한 책임은 이용자에게 있습니다. 다만, 회사의 고의 또는 과실이 있는 경우에는 그러하지 아니합니다.</li>\n                    <li>이용자는 외부 계정의 도용이 의심되는 경우 즉시 해당 외부 서비스의 보안 조치를 취하고 회사에 통지하여야 합니다.</li>\n                    <li>외부 서비스(Google 등)의 장애 또는 정책 변경으로 인해 로그인이 불가능할 경우, 회사의 고의 또는 중과실이 없는 한 회사는 이에 대해 책임지지 않습니다.</li>\n                    <li>이용자는 서비스 내 개인정보관리화면을 통하여 본인의 정보를 열람하고 수정할 수 있습니다. 정보가 변경되었을 경우 즉시 수정해야 하며, 이를 수정하지 않아 발생한 불이익에 대하여 회사는 책임지지 않습니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제8조 -->\n        <section id=\"a8\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제8조</span> 이용자에 대한 통지</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>회사가 이용자에 대한 통지를 하는 경우 이용자가 등록한 이메일 등으로 통지할 수 있습니다.</li>\n                    <li>회사는 불특정다수 이용자에 대한 통지의 경우 7일 이상 서비스 공지사항에 게시함으로써 제1항의 통지에 갈음할 수 있습니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제9조 -->\n        <section id=\"a9\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제9조</span> 회사의 의무</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>회사는 관련법과 본 약관이 금지하거나 미풍양속에 반하는 행위를 하지 않으며, 계속적이고 안정적으로 서비스를 제공하기 위하여 최선을 다하여 노력합니다.</li>\n                    <li>회사는 이용자가 안전하게 서비스를 이용할 수 있도록 개인정보 보호를 위해 보안시스템을 갖추어야 하며 개인정보처리방침을 공시하고 준수합니다.</li>\n                    <li>회사는 서비스 제공과 관련하여 알고 있는 이용자의 개인정보를 이용자의 승낙 없이 제3자에게 누설, 배포하지 않습니다. 다만, 관계법령에 의한 적법한 절차에 의한 경우에는 그러하지 않습니다.</li>\n                    <li>회사는 이용자에게 제공하는 유료서비스를 계속적이고 안정적으로 제공하기 위하여 설비에 장애가 생기거나 멸실되었을 때 지체 없이 이를 수리 또는 복구합니다. 다만, 천재지변이나 비상사태 등 부득이한 경우에는 서비스를 일시 중단할 수 있습니다.</li>\n                    <li>회사는 이용자로부터 제기되는 의견이나 불만이 정당하다고 인정할 경우에는 즉시 처리하여야 합니다. 다만, 즉시 처리가 곤란한 경우는 이용자에게 그 사유와 처리일정을 이메일 등으로 통보하여야 합니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제10조 -->\n        <section id=\"a10\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제10조</span> 이용자의 의무</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>이용자는 다음 행위를 하여서는 안 됩니다.\n                        <ul>\n                            <li>서비스 이용 신청 또는 변경 시 허위내용을 등록하는 행위</li>\n                            <li>타인의 정보나 명의를 도용하거나 부정하게 사용하는 행위</li>\n                            <li>다른 이용자의 개인정보를 동의 없이 수집, 저장, 공개하는 행위</li>\n                            <li>회사 또는 제3자의 저작권 등 지식재산권에 대한 침해 행위</li>\n                            <li>회사 또는 제3자의 명예를 손상시키거나 업무를 방해하는 행위</li>\n                            <li>서비스를 역설계, 디컴파일 또는 해킹하려는 시도</li>\n                            <li>자동화된 스크립트나 봇을 사용하여 서비스에 접근하는 행위 (제공된 기능을 통한 접근 제외)</li>\n                            <li>서비스 또는 서버에 대한 방해 또는 교란 행위, 대량의 트래픽을 발생시키는 행위</li>\n                            <li>악성코드, 바이러스 또는 유해한 코드를 전송하는 행위</li>\n                            <li>회사의 동의 없이 본 약관의 목적 범위를 벗어나 영리를 목적으로 서비스를 사용하는 행위</li>\n                            <li>제3자에게 임의로 서비스를 임대하거나 재판매하는 행위</li>\n                            <li>오픈마켓의 이용약관 또는 셀러 정책을 위반하는 행위</li>\n                            <li>현행 법령, 본 약관 및 회사가 공지한 이용 규정을 위반하는 행위</li>\n                        </ul>\n                    </li>\n                    <li>이용자는 관계법, 본 약관의 규정, 이용안내 및 서비스와 관련하여 공지한 주의사항을 준수하여야 하며, 기타 회사의 업무에 방해되는 행위를 하여서는 안 됩니다.</li>\n                    <li>이용자는 회사가 정한 서비스 이용요금을 지정된 날짜에 납입할 의무가 있습니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제11조 -->\n        <section id=\"a11\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제11조</span> 서비스 제공</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>회사가 제공하는 서비스의 주요 내용은 다음과 같으며, 세부사항은 홈페이지에 게시합니다.\n                        <ul>\n                            <li>복수 오픈마켓 스토어의 통합 대시보드 관리</li>\n                            <li>주문 정보 동기화 및 처리</li>\n                            <li>상품 등록 및 재고 관리</li>\n                            <li>매출 분석 및 성과 지표 제공</li>\n                            <li>배송 및 물류 자동화 (송장 출력, First Mile 사전신고 등)</li>\n                            <li>AI 기반 상품 설명 생성 등 부가 서비스</li>\n                        </ul>\n                    </li>\n                    <li>서비스는 연중무휴, 1일 24시간 제공함을 원칙으로 합니다. 단, 회사는 서비스 제공에 필요한 경우 정기점검을 실시할 수 있으며 정기점검시간은 사전에 공지한 바에 따릅니다.</li>\n                    <li>회사는 다음 각 호에 해당하는 경우 서비스의 전부 또는 일부를 제한하거나 중지할 수 있습니다.\n                        <ul>\n                            <li>서비스용 설비의 보수 등 공사로 인한 부득이한 경우</li>\n                            <li>정전, 제반 설비의 장애 또는 이용량의 폭주 등으로 정상적인 서비스 이용에 지장이 있는 경우</li>\n                            <li>천재지변, 국가비상사태 등 불가항력적 사유가 있는 경우</li>\n                            <li>기타 서비스를 유지할 수 없는 중대한 사유가 발생한 경우</li>\n                        </ul>\n                    </li>\n                    <li>본 조 제3항의 경우 회사는 제8조에서 정한 방법으로 이용자에게 통지합니다. 다만, 사전에 통지할 수 없는 부득이한 사유가 있는 경우 사후에 통지할 수 있습니다.</li>\n                    <li>회사는 무료 서비스(무료체험 등) 이용 시 이용자가 업로드하는 데이터를 관리해야 할 의무가 없으며, 무료 서비스 이용과 관련한 어떠한 책임도 부담하지 않습니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제12조 -->\n        <section id=\"a12\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제12조</span> 서비스의 변경 또는 중단</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>회사는 정책, 운영, 기술상 필요에 따라 제공하고 있는 서비스의 전부 또는 일부를 변경하거나 중단할 수 있습니다.</li>\n                    <li>서비스 내용 등에 변경이 있는 경우 변경 사유, 변경 내용 및 제공일자 등을 홈페이지 또는 공지사항에 게시합니다.</li>\n                    <li>회사는 다음의 권리를 가집니다.\n                        <ul>\n                            <li>서비스의 기능을 수정, 일시정지 또는 중단할 수 있음</li>\n                            <li>서비스 개선 또는 오류 수정을 위해 업데이트할 수 있음</li>\n                            <li>기존 구독자에게 30일 전 고지 후 가격을 변경할 수 있음</li>\n                        </ul>\n                    </li>\n                    <li>회사가 사업종목의 전환, 사업의 포기, 업체 간의 통합 등의 이유로 서비스를 제공할 수 없게 되는 경우, 회사는 제8조에서 정한 방법으로 이용자에게 통지하고 서비스를 종료할 수 있습니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제13조 -->\n        <section id=\"a13\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제13조</span> 서비스 이용의 제한 및 정지</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>회사는 관련법을 위반한 경우(명의도용, 결제도용, 해킹, 악성프로그램 배포, 접속권한 초과행위 등)에는 즉시 영구이용정지를 할 수 있습니다. 본 항에 따른 서비스 이용정지 시 서비스 내의 혜택 및 권리 등도 모두 소멸되며 회사는 이에 대해 별도로 보상하지 않습니다.</li>\n                    <li>회사는 다음 각 호에 해당하는 경우에 이용자의 서비스 이용을 제한할 수 있습니다.\n                        <ul>\n                            <li>이용자가 서비스 이용기간 만료 후에도 이용요금을 납부하지 않을 경우</li>\n                            <li>제10조에 규정된 이용자의 의무를 이행하지 아니한 경우</li>\n                            <li>이용자의 이용 규모(주문건수, 연동 스토어 수 등)가 구독 요금제별 정해진 기준을 초과할 경우</li>\n                            <li>이용자 정보가 정확하지 않은 경우</li>\n                            <li>다른 이용자 또는 제3자의 지식재산권을 침해하거나 명예를 손상시킨 경우</li>\n                            <li>공공질서 및 미풍양속에 저해되는 내용을 고의로 유포시킨 경우</li>\n                            <li>이용자가 서비스에 대량의 트래픽을 발생시키거나 서비스 운영에 지장을 주는 경우</li>\n                            <li>기타 회사가 이용자로 부적당하다고 판단한 경우</li>\n                        </ul>\n                    </li>\n                    <li>회사가 본 조에 의하여 서비스를 제한 또는 정지하는 경우, 그 사실을 이용자에게 사전 통보하여야 합니다. 다만, 사전에 통보하는 것이 곤란할 경우 이용정지 조치 후 통보할 수 있습니다.</li>\n                    <li>회사는 12개월 이상 서비스를 이용하지 아니하는 이용자의 개인정보를 보호하기 위해 이용자의 계정을 휴면계정으로 분류하고 서비스 이용계약을 해지하거나 개인정보의 파기 또는 별도 분리보관 등 필요한 조치를 할 수 있습니다.</li>\n                    <li>회사는 휴면계정으로 분류되기 30일 전까지 개인정보가 파기되거나 분리되어 저장되는 사실과 기간 만료일 및 해당 개인정보의 항목을 이메일 등으로 이용자에게 알리도록 합니다.</li>\n                    <li>본 조에 의한 서비스 이용 정지 또는 이용계약의 해지 시 데이터 삭제에 대한 책임은 이용자가 부담하며, 회사는 고의 또는 과실이 없는 한 데이터 삭제에 따른 책임을 부담하지 않습니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제14조 -->\n        <section id=\"a14\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제14조</span> 오픈마켓 연동 및 API 사용</h2>\n            <div class=\"legal-body\">\n                <p class=\"legal-sub\">14.1 API 연동 승인</p>\n                <p>이용자가 오픈마켓 스토어를 유니스오더에 연결함으로써, 회사에 다음 행위를 수행할 권한을 부여합니다.</p>\n                <ul>\n                    <li>해당 오픈마켓이 제공하는 오픈 API를 통한 스토어 데이터 접근</li>\n                    <li>주문, 상품, 매출 정보의 조회 및 동기화</li>\n                    <li>이용자의 지시에 따른 상품 등록 및 재고 변경</li>\n                    <li>이용자를 대신한 주문 처리 및 상태 업데이트</li>\n                </ul>\n\n                <p class=\"legal-sub\">14.2 오픈마켓 API 관련 고지</p>\n                <p>이용자는 다음 사항을 인지하고 동의합니다.</p>\n                <ul>\n                    <li>유니스오더의 연동 기능은 각 오픈마켓이 제공하는 API의 가용성 및 정책에 의존합니다.</li>\n                    <li>오픈마켓은 언제든지 API 접근을 변경, 제한 또는 종료할 수 있습니다.</li>\n                    <li>이용자는 연동된 오픈마켓의 이용약관 및 셀러 정책을 준수할 의무가 있습니다.</li>\n                    <li>이용자는 연동된 오픈마켓 셀러 계정을 정상 상태로 유지할 책임이 있습니다.</li>\n                    <li>유니스오더는 특정 오픈마켓과 제휴, 보증 또는 공식 연결 관계에 있지 않습니다.</li>\n                </ul>\n\n                <p class=\"legal-sub\">14.3 연동 해제</p>\n                <p>이용자는 언제든지 해당 오픈마켓 셀러센터 설정 또는 유니스오더 계정 설정을 통해 연동을 해제할 수 있습니다. 연동 해제 시 해당 스토어의 관리 기능이 비활성화되며, 서비스 기능에 제한이 발생할 수 있습니다.</p>\n\n                <p class=\"legal-sub\">14.4 오픈마켓 정책 변경에 따른 면책</p>\n                <p>오픈마켓이 API 연동 방식을 차단하거나 정책을 변경하는 등 회사가 오픈마켓과의 연동을 유지할 수 없는 사정이 발생한 경우, 회사는 연동을 중단할 수 있으며 이 경우 이용자에게 발생한 손해에 대해서는 책임을 부담하지 않습니다.</p>\n            </div>\n        </section>\n\n        <!-- 제15조 -->\n        <section id=\"a15\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제15조</span> AI 기능 이용 준수사항</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>회사는 이용자가 서비스의 전부 또는 일부에서 AI 기술 기반의 부가 기능(이하 'AI 기능')을 이용할 수 있도록 제공할 수 있습니다.</li>\n                    <li>회사는 본 AI 기능 제공을 위해 직접 또는 제3자에게 업무를 위탁하는 방식으로 이용자의 데이터를 처리할 수 있습니다. 이용자의 데이터는 본 AI 기능 제공 목적으로만 활용되고 제3자를 위한 학습데이터에 활용 또는 제공되지 않습니다.</li>\n                    <li>AI 기능을 통해 생성된 콘텐츠(상품 설명 등)에는 부적절하거나 부정확한 내용 또는 저작권 등 타인의 권리를 침해하는 사항이 포함될 수 있으며, 이용자는 AI 생성 콘텐츠를 이용하기 전 해당 내용의 진위 또는 법령위반 여부 등을 확인할 주의의무가 있습니다. 회사는 AI 생성 콘텐츠의 정확성, 품질, 적합성을 보장하지 않습니다.</li>\n                    <li>이용자는 AI 기능에 입력하는 데이터에 타인의 저작물 등 권리를 침해하거나 그러한 우려가 있는 내용, 타인의 비밀에 관한 사항, 기타 관련 법령을 위반하는 사항을 포함시켜서는 안됩니다.</li>\n                    <li>오픈마켓 스토어에 게시되는 AI 생성 콘텐츠에 대한 모든 책임은 이용자에게 있습니다.</li>\n                    <li>회사는 이용자가 본 조를 위반하여 발생하는 문제 또는 분쟁에 대하여 책임을 부담하지 않습니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제16조 -->\n        <section id=\"a16\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제16조</span> 구독 및 결제</h2>\n            <div class=\"legal-body\">\n                <p class=\"legal-sub\">16.1 요금제</p>\n                <p>유니스오더는 다양한 기능과 가격의 구독 요금제를 제공합니다. 현재 요금 정보는 웹사이트에서 확인할 수 있으며, 합리적인 사전 고지 후 변경될 수 있습니다. 모든 가격은 VAT(부가가치세) 포함 금액입니다.</p>\n\n                <p class=\"legal-sub\">16.2 결제</p>\n                <ul>\n                    <li>구독 요금은 월 단위로 선불 자동 결제됩니다.</li>\n                    <li>결제일은 최초 유료 구독 시작일을 기준으로 매월 동일 일자에 자동 청구됩니다.</li>\n                    <li>이용자는 등록된 결제 수단으로의 자동 청구에 동의합니다.</li>\n                    <li>결제 실패 시 3일 이내 재시도하며, 재시도 실패 시 서비스가 일시 중지될 수 있습니다.</li>\n                    <li>결제 처리는 토스페이먼츠(주)를 통해 이루어집니다.</li>\n                </ul>\n\n                <p class=\"legal-sub\">16.3 무료체험</p>\n                <p>유니스오더는 신규 가입자를 대상으로 7일간의 무료체험 기간을 제공합니다.</p>\n                <ul>\n                    <li>무료체험 기간 동안 결제 정보 등록 없이 서비스를 이용할 수 있습니다.</li>\n                    <li>무료체험 종료 후 유료 구독을 원하실 경우 결제 정보를 등록해 주세요.</li>\n                    <li>무료체험 종료 시 자동으로 유료 전환되지 않습니다.</li>\n                    <li>무료체험은 1인(1계정)당 1회에 한합니다.</li>\n                </ul>\n\n                <p class=\"legal-sub\">16.4 정기결제</p>\n                <ul>\n                    <li>이용자는 정기결제 신청 시 결제수단(신용카드)을 사전에 등록해야 합니다.</li>\n                    <li>회사는 서비스 갱신일(이용기간 만료일의 익일)의 4일 전 이용자가 등록한 결제수단으로 이용요금을 결제합니다.</li>\n                    <li>정기결제가 실패한 경우 이용자는 서비스 갱신일의 전일까지 결제수단을 재등록하는 등 필요한 조치를 취하여야 합니다.</li>\n                    <li>서비스 갱신일의 전일까지 결제가 실패될 경우 정기결제가 일시 정지되며, 서비스 갱신일부터 서비스 이용이 정지됩니다.</li>\n                    <li>정기결제는 이용자의 해지 신청 또는 환불 신청 시 해지됩니다.</li>\n                </ul>\n\n                <p class=\"legal-sub\">16.5 서비스 이용의 연속성</p>\n                <p>회사는 안정적이고 연속적인 서비스를 제공하기 위하여 별도의 서비스 일시정지 기능을 제공하지 않습니다. 이용자의 개인 사정이나 단순 변심으로 인한 이용 기간의 중단 또는 연장은 불가합니다.</p>\n            </div>\n        </section>\n\n        <!-- 제17조 -->\n        <section id=\"a17\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제17조</span> 이용요금 등의 환불</h2>\n            <div class=\"legal-body\">\n                <p>유니스오더의 환불 정책은 「전자상거래 등에서의 소비자보호에 관한 법률」에 따릅니다.</p>\n                <ol>\n                    <li>회사는 서비스 이용요금 등의 과납 또는 오납이 있을 때에는 그 과납 또는 오납된 이용요금을 반환합니다.</li>\n                    <li>회원의 환불 요청에 따른 환불 기준은 다음과 같습니다.\n                        <ul>\n                            <li><strong>결제 후 7일 이내, 서비스 미이용 시:</strong> 전액 환불 (단, 서비스 미이용이란 결제 이후 1회도 로그인하여 서비스 기능을 사용하지 않은 경우를 의미합니다.)</li>\n                            <li><strong>결제 후 7일 경과 또는 서비스 이용 시:</strong> 이용일수에 해당하는 금액과 위약금(잔여 이용요금의 10%)을 공제한 잔액을 환불</li>\n                        </ul>\n                    </li>\n                    <li>구독 유형별 일할 계산 기준은 다음과 같습니다.\n                        <ul>\n                            <li><strong>월간 결제 회원:</strong> 월 기준 30일로 산정하며, 월 이용요금을 30으로 나눈 금액을 일할 단가로 합니다.</li>\n                            <li><strong>연간 결제 회원:</strong> 연 기준 365일로 산정하되, 이용일수에 해당하는 금액은 월간 정상가를 기준으로 일할 계산합니다. (연간 할인이 적용된 요금제의 경우, 환불 시 이미 이용한 기간은 월간 정상가 기준으로 재산정됩니다.)</li>\n                        </ul>\n                    </li>\n                    <li>프로모션, 할인쿠폰 또는 특별 할인이 적용된 결제건의 환불 시, 이미 이용한 기간에 대해서는 할인 전 정상가를 기준으로 이용요금을 산정하며, 산정된 이용요금과 위약금을 공제한 잔액을 환불합니다. 공제 금액이 결제 금액을 초과하는 경우 환불 금액은 없습니다.</li>\n                    <li>회사의 귀책사유로 인한 환불은 다음과 같이 처리됩니다.\n                        <ul>\n                            <li><strong>결제 오류 및 중복 결제:</strong> 확인 후 해당 금액 전액 환불</li>\n                            <li><strong>서비스 장애로 인한 이용 불가:</strong> 연속 24시간 이상 서비스 전체 이용이 불가능한 경우에 한하여, 장애 기간만큼 이용 기간을 연장하는 것을 원칙으로 합니다. 이용자가 이용 기간 연장 대신 환불을 요청하는 경우 장애 일수에 해당하는 금액을 일할 환불합니다.</li>\n                            <li>회사의 귀책사유가 명백한 경우에는 위약금이 공제되지 않습니다.</li>\n                        </ul>\n                    </li>\n                    <li>환불 시에는 PG사 결제 수수료, 송금 수수료 등 실비가 공제될 수 있습니다. 단, 본 조 제5항의 회사 귀책사유에 해당하는 경우는 제외합니다.</li>\n                    <li>환불 신청은 결제일로부터 90일 이내에 고객센터(이메일: <a href=\"mailto:contact@hourgrit.com\">contact@hourgrit.com</a>, 카카오톡 채널: @unisorder)로 요청해 주시기 바랍니다. 기한 경과 후의 환불 요청은 회사의 재량에 따라 처리됩니다.</li>\n                    <li>환불은 접수일로부터 영업일 기준 3~5일 이내 처리되며, 환불 금액은 원래 결제 수단으로 반환됩니다. 결제 수단의 사정에 따라 환불이 지연될 수 있으며, 이 경우 회사는 책임을 부담하지 않습니다.</li>\n                    <li>다음의 경우 「전자상거래 등에서의 소비자보호에 관한 법률」 제17조 제2항에 따라 청약철회가 제한될 수 있습니다.\n                        <ul>\n                            <li>이용자의 요청에 따라 개별적으로 구성된 맞춤형 서비스 또는 디지털 콘텐츠</li>\n                            <li>서비스 이용이 개시된 경우 (로그인 후 서비스 기능을 1회 이상 사용한 경우를 포함하며, 사전에 청약철회 제한에 대해 고지하고 동의를 받은 경우에 한함)</li>\n                            <li>무료체험 기간 종료 후 유료 전환하여 서비스를 계속 이용한 경우</li>\n                        </ul>\n                    </li>\n                    <li>이용자가 본 약관을 위반하여 회사에 의해 서비스 이용이 정지 또는 해지된 경우, 이용자는 이미 납부한 이용요금의 환불을 청구할 수 없습니다.</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제18조 -->\n        <section id=\"a18\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제18조</span> 이용계약 해지</h2>\n            <div class=\"legal-body\">\n                <p class=\"legal-sub\">18.1 이용자에 의한 해지</p>\n                <p>이용자는 언제든지 계정 설정에서 구독을 취소하거나 고객센터(이메일: <a href=\"mailto:contact@hourgrit.com\">contact@hourgrit.com</a>, 카카오톡 채널: @unisorder)에 연락하여 이용계약을 해지할 수 있습니다.</p>\n\n                <p class=\"legal-sub\">18.2 회사에 의한 해지</p>\n                <p>회사는 본 조 제2항의 해지신청이 접수되면 즉시 이용계약을 해지합니다. 단, 별도의 채권·채무관계가 있을 경우에는 그러하지 아니합니다.</p>\n\n                <p class=\"legal-sub\">18.3 회사에 의한 강제 해지</p>\n                <p>회사는 이용자가 다음 각 호에 해당할 경우에는 이용자의 동의 없이 이용계약을 해지할 수 있으며, 그 사실을 이용자에게 통지합니다.</p>\n                <ul>\n                    <li>타인의 명의로 서비스 계약을 체결하였거나 제출한 정보가 허위 또는 누락되었음이 확인된 경우</li>\n                    <li>이용자가 본 약관을 위반하고 일정 기간 이내에 위반 내용을 해소하지 않는 경우</li>\n                    <li>회사의 서비스 제공목적 외의 용도로 서비스를 이용하거나 제3자에게 임의로 서비스를 임대한 경우</li>\n                    <li>결제가 실패하거나 이용료가 체납된 경우</li>\n                    <li>사기 또는 불법 행위가 의심되는 경우</li>\n                    <li>제13조 규정에 의하여 이용정지를 당한 이후 1년 이내에 이용정지 사유가 재발한 경우</li>\n                    <li>법령에 의해 요구되거나 회사의 권리를 보호해야 하는 경우</li>\n                </ul>\n\n                <p class=\"legal-sub\">18.4 해지의 효과</p>\n                <ul>\n                    <li>서비스 접근 권한이 즉시 정지됩니다.</li>\n                    <li>관련법 및 개인정보처리방침에 따라 회사가 이용자 정보를 보유하는 경우를 제외하고는 해지 즉시 이용자의 모든 데이터는 소멸될 수 있으며, 소멸된 데이터는 어떤 경우에도 반환되지 않습니다.</li>\n                    <li>이용자는 서비스의 모든 이용을 중단하여야 합니다.</li>\n                    <li>책임, 손해배상, 분쟁 해결에 관한 조항은 해지 후에도 유효합니다.</li>\n                </ul>\n            </div>\n        </section>\n\n        <!-- 제19조 -->\n        <section id=\"a19\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제19조</span> 데이터의 보관 및 삭제</h2>\n            <div class=\"legal-body\">\n                <p>서비스 이용 과정에서 생성·저장되는 데이터는 관련 법령에 정해진 기간 또는 이용자와 별도 합의한 기간 동안 보관 후 삭제됩니다.</p>\n                <table class=\"legal-table\">\n                    <thead>\n                        <tr>\n                            <th>데이터 항목</th>\n                            <th>보관기간</th>\n                        </tr>\n                    </thead>\n                    <tbody>\n                        <tr><td>주문정보</td><td>서비스 이용기간 + 법정 보존기간(5년)</td></tr>\n                        <tr><td>상품정보</td><td>서비스 이용기간 + 90일</td></tr>\n                        <tr><td>통계 데이터, 상품 정보 변경 이력</td><td>서비스 이용기간</td></tr>\n                        <tr><td>재고 데이터</td><td>서비스 이용기간</td></tr>\n                    </tbody>\n                </table>\n            </div>\n        </section>\n\n        <!-- 제20조 -->\n        <section id=\"a20\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제20조</span> 지식재산권</h2>\n            <div class=\"legal-body\">\n                <p class=\"legal-sub\">20.1 회사의 권리</p>\n                <p>유니스오더의 소프트웨어, 디자인, 상표, 콘텐츠를 포함한 일체의 지식재산권은 회사에 귀속되며, 관련 법률의 보호를 받습니다. 이용자는 서비스 또는 콘텐츠를 복제, 수정, 배포하거나 회사의 상표 또는 브랜드를 무단 사용하여서는 안 됩니다.</p>\n\n                <p class=\"legal-sub\">20.2 이용자의 데이터</p>\n                <p>이용자는 자신의 사업 데이터, 상품 등록 정보 및 콘텐츠에 대한 모든 권리를 보유합니다. 이용자는 유니스오더 이용을 통해 회사에 다음의 제한적 라이선스를 부여합니다.</p>\n                <ul>\n                    <li>서비스 제공을 위한 데이터의 저장 및 처리</li>\n                    <li>서비스 내에서 이용자 데이터의 표시</li>\n                    <li>분석 및 서비스 개선을 위한 집계·익명화된 데이터의 활용</li>\n                </ul>\n\n                <p class=\"legal-sub\">20.3 이용자의 책임</p>\n                <p>이용자가 서비스를 통하여 업로드하는 이미지나 자료가 제3자의 저작권 및 지식재산권을 침해하여서는 안되며, 이로 인해 발생하는 모든 문제는 전적으로 이용자의 책임입니다.</p>\n            </div>\n        </section>\n\n        <!-- 제21조 -->\n        <section id=\"a21\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제21조</span> 면책조항 및 책임 제한</h2>\n            <div class=\"legal-body\">\n                <p class=\"legal-sub\">21.1 서비스 \"현상태\" 제공</p>\n                <p>유니스오더는 \"현재 상태(AS IS)\" 및 \"이용 가능한 범위(AS AVAILABLE)\" 내에서 제공되며, 다음을 포함한 명시적 또는 묵시적 보증을 하지 않습니다.</p>\n                <ul>\n                    <li>데이터의 정확성, 신뢰성 또는 완전성</li>\n                    <li>중단 없는 또는 오류 없는 운영</li>\n                </ul>\n\n                <p class=\"legal-sub\">21.2 제3자 서비스</p>\n                <p>회사는 다음에 대해 책임을 지지 않습니다.</p>\n                <ul>\n                    <li>오픈마켓 플랫폼의 가용성, 정책 또는 변경 사항</li>\n                    <li>제3자 서비스 제공자(호스팅, AI, 결제 대행사 등)의 장애</li>\n                    <li>인터넷 연결 또는 네트워크 장애</li>\n                    <li>오픈마켓이 이용자의 셀러 계정에 대해 취하는 조치</li>\n                </ul>\n\n                <p class=\"legal-sub\">21.3 책임 제한</p>\n                <p>관련 법령이 허용하는 최대 범위 내에서, 회사는 다음에 대해 책임을 지지 않습니다.</p>\n                <ul>\n                    <li>간접적, 부수적, 특별, 결과적 또는 징벌적 손해</li>\n                    <li>이익, 매출, 데이터 또는 사업 기회의 손실</li>\n                    <li>서비스 중단 또는 데이터 손실</li>\n                    <li>AI 생성 콘텐츠 또는 자동화된 프로세스의 오류</li>\n                </ul>\n                <p>회사의 총 책임액은 해당 청구일 전 12개월간 이용자가 회사에 지급한 금액을 초과하지 않습니다.</p>\n\n                <p class=\"legal-sub\">21.4 추가 면책</p>\n                <ul>\n                    <li>회사는 이용자가 서비스를 통해 얻은 정보 또는 자료 등으로 인해 발생한 손해에 대하여 책임을 면합니다.</li>\n                    <li>회사는 이용자 상호 간 또는 이용자와 제3자 상호 간에 서비스를 매개로 하여 거래 등을 한 경우에는 책임을 면합니다.</li>\n                    <li>회사는 무료로 제공하는 서비스 이용과 관련하여 관련법에 특별한 규정이 없는 한 책임을 지지 않습니다.</li>\n                    <li>회사는 제13조 및 제19조에 따라 파기된 데이터와 이용자가 직접 삭제를 요청한 데이터에 대해서는 책임을 지지 않습니다.</li>\n                </ul>\n            </div>\n        </section>\n\n        <!-- 제22조 -->\n        <section id=\"a22\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제22조</span> 손해배상</h2>\n            <div class=\"legal-body\">\n                <p>이용자는 다음의 사유로 발생하는 청구, 손해, 손실 또는 비용(법률 비용 포함)에 대해 회사 및 그 임직원을 면책하고 방어할 것에 동의합니다.</p>\n                <ul>\n                    <li>이용자의 서비스 이용</li>\n                    <li>본 약관의 위반</li>\n                    <li>법령 또는 제3자 권리의 침해</li>\n                    <li>이용자의 오픈마켓 셀러 활동</li>\n                    <li>이용자가 서비스를 통해 게시한 콘텐츠 또는 수행한 행위</li>\n                </ul>\n            </div>\n        </section>\n\n        <!-- 제23조 -->\n        <section id=\"a23\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제23조</span> 불만처리</h2>\n            <div class=\"legal-body\">\n                <ol>\n                    <li>회사는 이용자의 의견을 수렴하고 불만을 처리하기 위한 절차를 마련하여야 합니다.</li>\n                    <li>회사는 다음 채널을 통하여 이용자의 불만사항을 접수, 처리합니다.\n                        <ul>\n                            <li>이메일: <a href=\"mailto:contact@hourgrit.com\">contact@hourgrit.com</a></li>\n                            <li>카카오톡 채널: @unisorder (<a href=\"https://pf.kakao.com/_unisorder\" target=\"_blank\" rel=\"noreferrer\">https://pf.kakao.com/_unisorder</a>)</li>\n                        </ul>\n                    </li>\n                    <li>고객지원 운영시간: 평일 10:00~18:00 KST (공휴일 제외), 응답 소요: 영업일 기준 48시간 이내</li>\n                </ol>\n            </div>\n        </section>\n\n        <!-- 제24조 -->\n        <section id=\"a24\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제24조</span> 준거법 및 분쟁 해결</h2>\n            <div class=\"legal-body\">\n                <p class=\"legal-sub\">24.1 준거법</p>\n                <p>본 약관은 대한민국 법률에 따라 규율되며 해석됩니다.</p>\n\n                <p class=\"legal-sub\">24.2 분쟁 해결</p>\n                <p>본 약관 또는 서비스 이용과 관련하여 발생하는 분쟁은 한국인터넷진흥원(KISA) 전자거래분쟁조정위원회의 조정 절차를 통해 해결을 시도하며, 조정이 성립하지 않을 경우 대전지방법원 천안지원을 관할 법원으로 합니다.</p>\n\n                <p class=\"legal-sub\">24.3 소비자 보호</p>\n                <p>본 약관에서 정하지 아니한 사항과 본 약관의 해석에 관하여는 「전자상거래 등에서의 소비자보호에 관한 법률」, 「약관의 규제에 관한 법률」, 및 관계 법령에 따릅니다.</p>\n\n                <p class=\"legal-sub\">24.4 해외 이용자</p>\n                <p>해외에 주소나 거소가 있는 이용자의 경우 회사와 이용자 간 발생한 분쟁에 관한 소송은 대한민국 서울중앙지방법원을 관할법원으로 합니다.</p>\n            </div>\n        </section>\n\n        <!-- 제25조 -->\n        <section id=\"a25\" class=\"legal-article\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\">제25조</span> 기타</h2>\n            <div class=\"legal-body\">\n                <p class=\"legal-sub\">25.1 완전합의</p>\n                <p>본 약관은 <a href=\"/privacy\">개인정보처리방침</a>과 함께 유니스오더와 관련하여 이용자와 회사 간의 완전한 합의를 구성합니다.</p>\n\n                <p class=\"legal-sub\">25.2 분리가능성</p>\n                <p>본 약관의 일부 조항이 무효이거나 집행 불가능한 것으로 판명되더라도, 나머지 조항은 완전한 효력을 유지합니다.</p>\n\n                <p class=\"legal-sub\">25.3 권리불포기</p>\n                <p>회사가 본 약관의 권리 또는 조항을 행사하지 않았다 하여 해당 권리 또는 조항을 포기한 것으로 보지 않습니다.</p>\n\n                <p class=\"legal-sub\">25.4 양도</p>\n                <p>이용자는 회사의 서면 동의 없이 본 약관을 양도하거나 이전할 수 없습니다. 회사는 본 약관을 언제든지 양도할 수 있습니다.</p>\n\n                <p class=\"legal-sub\">25.5 불가항력</p>\n                <p>회사는 천재지변, 전쟁, 전염병, 인프라 장애 등 합리적인 통제 범위를 벗어난 사유로 인한 지연 또는 이행 불가에 대해 책임을 지지 않습니다.</p>\n            </div>\n        </section>\n\n        <!-- 부칙 -->\n        <section class=\"legal-article\" style=\"border-top: 2px solid var(--gray-300);\">\n            <h2 class=\"legal-article-header\"><span class=\"legal-badge\" style=\"background:var(--gray-700);\">부칙</span></h2>\n            <div class=\"legal-body\">\n                <p>본 약관은 <strong>2026년 3월 13일</strong>부터 시행합니다.</p>\n            </div>\n        </section>\n    </article>";
